70	export function pointInPolygonMm(point: XY, polygon: XY[], boundaryToleranceMm = 0.5): boolean {
71	  if (polygon.length < 3) return false;
72	
73	  for (let i = 0; i < polygon.length; i++) {
74	    const a = polygon[i]!;
75	    const b = polygon[(i + 1) % polygon.length]!;
76	    if (pointOnSegmentMm(point, a, b, boundaryToleranceMm)) return true;
77	  }
78	
79	  let inside = false;
80	  for (let i = 0, j = polygon.length - 1; i < polygon.length; j = i++) {
81	    const pi = polygon[i]!;
82	    const pj = polygon[j]!;
83	    const crossesY = pi.yMm > point.yMm !== pj.yMm > point.yMm;
84	    if (!crossesY) continue;
85	
86	    const xAtY = ((pj.xMm - pi.xMm) * (point.yMm - pi.yMm)) / (pj.yMm - pi.yMm) + pi.xMm;
87	    if (point.xMm < xAtY) inside = !inside;
88	  }
89	  return inside;
90	}
