    case 'roofs':
      return sidRoofs;
    case 'stairs':
      return sidStairs;
    case 'plans':
      return sidPlans;
    case 'views':
      return sidViews;
    case 'sheets':
      return sidSheets;
    case 'assemblies':
      return sidAssemblies;
    default:
      return undefined;
  }
}, [
  tab,
  sidRooms,
  sidDoors,
  sidWins,
  sidFinishes,
  sidFloors,
  sidRoofs,
  sidStairs,
  sidPlans,
  sidViews,
  sidSheets,
  sidAssemblies,
]);

