import type { Element } from '@bim-ai/core';

import { pointInPolygonMm } from '../plan/areaPlacement';
import { polygonAreaMm2 } from '../plan/symbology';
import { buildLevelDatumStackRows, levelIdsFromDatumRows } from '../workspace/readouts';

export type LevelAreaRow = {
  levelId: string;
  levelName: string;
  grossAreaM2: number;
  netAreaM2: number;
};

export function buildLevelAreaReport(
  elementsById: Record<string, Element>,
): LevelAreaRow[] {
  type LevelEl = Extract<Element, { kind: 'level' }>;
  type FloorEl = Extract<Element, { kind: 'floor' }>;
  type ColumnEl = Extract<Element, { kind: 'column' }>;
  type WallEl = Extract<Element, { kind: 'wall' }>;

  const levels: LevelEl[] = [];
  const floors: FloorEl[] = [];
  const columns: ColumnEl[] = [];
  const walls: WallEl[] = [];

  for (const el of Object.values(elementsById)) {
    if (el.kind === 'level') levels.push(el as LevelEl);
    else if (el.kind === 'floor') floors.push(el as FloorEl);
    else if (el.kind === 'column') columns.push(el as ColumnEl);
    else if (el.kind === 'wall') walls.push(el as WallEl);
  }

  const levelById = new Map<string, LevelEl>(levels.map((l) => [l.id, l]));

  const floorsByLevel = new Map<string, FloorEl[]>();
  for (const f of floors) {
    const arr = floorsByLevel.get(f.levelId) ?? [];
    arr.push(f);
    floorsByLevel.set(f.levelId, arr);
  }

  const rows: LevelAreaRow[] = [];

  for (const [levelId, levelFloors] of floorsByLevel) {
    const levelEl = levelById.get(levelId);
    const levelName = levelEl?.name ?? levelId;

    let grossMm2 = 0;
    let deductMm2 = 0;

    const levelColumns = columns.filter((c) => c.levelId === levelId);
    const levelWalls = walls.filter((w) => w.levelId === levelId);

    for (const floor of levelFloors) {
      const boundary = floor.boundaryMm;
      grossMm2 += polygonAreaMm2(boundary);

      for (const col of levelColumns) {
        if (pointInPolygonMm(col.positionMm, boundary)) {
          deductMm2 += col.bMm * col.hMm;
        }
      }

      for (const wall of levelWalls) {
        const mid = {
          xMm: (wall.start.xMm + wall.end.xMm) / 2,
          yMm: (wall.start.yMm + wall.end.yMm) / 2,
        };
        if (pointInPolygonMm(mid, boundary)) {
          const len = Math.hypot(
            wall.end.xMm - wall.start.xMm,
            wall.end.yMm - wall.start.yMm,
          );
          deductMm2 += len * wall.thicknessMm;
        }
      }
    }

    rows.push({
      levelId,
      levelName,
      grossAreaM2: grossMm2 / 1e6,
      netAreaM2: Math.max(0, grossMm2 - deductMm2) / 1e6,
    });
  }

  rows.sort((a, b) => {
    const eA = levelById.get(a.levelId)?.elevationMm ?? 0;
    const eB = levelById.get(b.levelId)?.elevationMm ?? 0;
    if (eA !== eB) return eA - eB;
    return a.levelName.localeCompare(b.levelName);
  });

  return rows;
}

